async function 问鼎天下_商店兑换(d) {
  var _dict, _id, backpack_id, data, material_name, max_level, name, need, now_level, possess, q, r, t, treasure;
  name = "神魔录";
  data = ({["夔牛鼓"]: ({["id"]: 1, ["t"]: 1270, ["backpack_id"]: 5154, ["material_name"]: "夔牛碎片"}), ["饕餮鼎"]: ({["id"]: 2, ["t"]: 1271, ["backpack_id"]: 5155, ["material_name"]: "饕餮碎片"}), ["烛龙印"]: ({["id"]: 3, ["t"]: 1268, ["backpack_id"]: 5156, ["material_name"]: "烛龙碎片"}), ["黄鸟伞"]: ({["id"]: 4, ["t"]: 1269, ["backpack_id"]: 5157, ["material_name"]: "黄鸟碎片"})});
  for (let [treasure, _dict] of pyItems(data)) {
    _id = _dict["id"];
    t = _dict["t"];
    backpack_id = _dict["backpack_id"];
    material_name = _dict["material_name"];
    possess = await c_get_material_quantity(d, backpack_id);
    await d.get(`cmd=ancient_gods&op=4&id=${_id}`);
    now_level = d.find("等级：(\\d+)");
    max_level = d.find("最高提升至(\\d+)");
    d.log(`${treasure} -> 当前 ${now_level} 级`, name);
    d.log(`${treasure} -> 最高 ${max_level} 级`, name);
    if ((now_level === max_level)) {
      continue;
    }
    need = d.find("碎片\\*(\\d+)");
    if ((need === null)) {
      d.log(`${treasure} -> 获取${material_name}需要数量失败`);
      continue;
    }
    need = pyInt(need);
    if ((need <= possess)) {
      continue;
    }
    d.log(`${treasure} -> 消耗${material_name}*${need}（${possess}）`, name);
    [q, r] = pyDivmod((need - possess), 10);
    if (pyTruthy(q)) {
      await d.get(`cmd=exchange&subtype=2&type=${t}&times=10&costtype=14`);
      d.log(`${treasure} -> ${d.find()}`);
      return;
    }
    for (let _ of pyRange(r)) {
      await d.get(`cmd=exchange&subtype=2&type=${t}&times=1&costtype=14`);
      d.log(`${treasure} -> ${d.find()}`);
    }
  }
}

