async function 问鼎天下(d) {
  var _id, count, is_cheered, region, remaining_occupy_count;
  if ((DateTime.week() === 1)) {
    await d.get("cmd=tbattle&op=drawreward");
    d.log(d.find());
    await 问鼎天下_商店兑换(d);
  }
  is_cheered = await 问鼎天下_助威(d);
  if ((contains(pySet([6, 7]), DateTime.week()))) {
    if (!pyTruthy(is_cheered)) {
      d.log("页面没有可助威入口");
    }
    return;
  }
  await d.get("cmd=tbattle");
  if ((contains(d.html, "放弃"))) {
    d.log("已有占领资源点，本任务结束");
    return;
  }
  if ((contains(d.html, "你占领的领地已经枯竭"))) {
    await d.get("cmd=tbattle&op=drawreleasereward");
    d.log(d.find());
  }
  remaining_occupy_count = d.find("剩余抢占次数：(\\d+)");
  if ((remaining_occupy_count === null)) {
    d.log("获取剩余抢占次数失败");
    return;
  }
  remaining_occupy_count = pyInt(remaining_occupy_count);
  if ((remaining_occupy_count === 0)) {
    d.log("没有抢占次数了");
    return;
  }
  region = d.config("问鼎天下.region");
  count = d.config("问鼎天下.count");
  if ((count >= remaining_occupy_count)) {
    count = pyMax(0, null);
  }
  await d.get(`cmd=tbattle&op=showregion&region=${region}`);
  for (let _id of pySlice(d.findall("id=(\\d+).*?攻占</a>"), null, 4)) {
    while (pyTruthy(count)) {
      await d.get(`cmd=tbattle&op=occupy&id=${_id}&region=${region}`);
      d.log(d.find());
      if ((contains(d.html, "你主动与"))) {
        count -= 1;
        if ((contains(d.html, "放弃"))) {
          await d.get("cmd=tbattle&op=abandon");
          d.log(d.find());
        }
      } else {
        break;
      }
    }
    if ((count === 0)) {
      break;
    }
  }
  await d.get(`cmd=tbattle&op=showregion&region=${region}`);
  _id = d.findall("id=(\\d+).*?攻占</a>")[(-1)];
  await d.get(`cmd=tbattle&op=occupy&id=${_id}&region=1`);
  d.log(d.find());
}

